import React from "react";
import { motion } from "framer-motion";
import "./styles/Home.css";

function Home() {
  return (
    <div className="home-container">

      {/* HERO */}
      <main className="hero">

        <motion.div
          className="hero-text"
          initial={{ opacity: 0, x: -80 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ duration: 1.2 }}
        >
          <h1>
            Where stories <br />
            <span className="italic-serif">sleep in shelves.</span>
          </h1>

          <p className="description">
            Welcome to a quiet corner of magic. A digital Hogwarts where books are
            guarded by dust, time, and gentle imagination.
          </p>

          <button className="main-cta">ENTER THE ARCHIVES</button>
        </motion.div>

        <motion.div
          className="hero-images"
          initial={{ opacity: 0, scale: 0.8 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ duration: 1.5 }}
        >
          <div className="image-wrapper main-img">
            <img
              src="https://images.unsplash.com/photo-1507842217343-583bb7270b66?q=80&w=1000"
              alt="Library"
            />
          </div>

          <div className="image-wrapper secondary-img">
            <img
              src="https://images.unsplash.com/photo-1524995997946-a1c2e315a42f?q=80&w=1000"
              alt="Books"
            />
          </div>

          <motion.div
            className="quote-card"
            animate={{ y: [0, -10, 0] }}
            transition={{ duration: 3, repeat: Infinity }}
          >
            "Words are the truest form of magic."
          </motion.div>
        </motion.div>

      </main>

      {/* FOOTER */}
      <footer className="footer">
        <div className="footer-line"></div>
        <p className="est">BookSphere • Est. MMXXVI</p>
      </footer>

    </div>
  );
}

export default Home;
